// Helper function to check if a hostname resolves to a private/internal IP address
func isInternalIP(host string) bool {
	// First check if it's directly an IP address
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
