	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF attacks by rejecting certain hosts
	host := strings.ToLower(parsedURL.Hostname())
	if isLocalhost(host) || isPrivateIP(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to local/network resources not allowed"})
	}

	// Fetch the URL
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Prevent redirects
		},
	}

	reqHTTP, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Limit size of content to prevent large memory allocation
	if len(body) > 2*1024*1024 { // 2MB limit
		body = body[:2*1024*1024]
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// Check if host is localhost
func isLocalhost(host string) bool {
	return host == "localhost" || 
		   host == "127.0.0.1" || 
		   host == "::1" ||
		   strings.HasPrefix(host, "127.")
}

// Check if host resolves to a private IP
func isPrivateIP(host string) bool {
	// This is a simplified check - in production you'd want to resolve the hostname and check if it's in private ranges
	privatePrefixes := []string{
		"10.",      // Class A private network
		"172.16.",  // Class B private networks (172.16.0.0-172.31.255.255)
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
		"192.168.", // Class C private network
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(host, prefix) {
			return true
		}
	}
	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string

	// Extract title
	titleSelection := doc.Find("title")
	if titleSelection.Length() > 0 {
		title = strings.TrimSpace(titleSelection.First().Text())
	} else {
		// Try og:title meta tag
		doc.Find("meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				title = strings.TrimSpace(val)
			}
		})
	}

	// Extract description
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if val, exists := s.Attr("content"); exists {
			description = strings.TrimSpace(val)
		}
	})

	// Fallback to og:description
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				description = strings.TrimSpace(val)
			}
		})
	}

	return title, description
}

