	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: fmt.Sprintf("Error creating request: %v", err),
		})
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: fmt.Sprintf("Error fetching URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: fmt.Sprintf("Received non-OK status code: %d", resp.StatusCode),
		})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: fmt.Sprintf("Error reading response body: %v", err),
		})
	}

	title, description := parseHTMLContent(body)

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func parseHTMLContent(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	// Extract title
	title := ""
	doc.Find("title").Each(func(i int, s *goquery.Selection) {
		title = strings.TrimSpace(s.Text())
	})

	// Extract meta description
	description := ""
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		desc, exists := s.Attr("content")
		if exists {
			description = strings.TrimSpace(desc)
		}
	})

	// Also check for og:description
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			desc, exists := s.Attr("content")
			if exists {
				description = strings.TrimSpace(desc)
			}
		})
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

