	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF by ensuring the host is not a private/internal address
	host := parsedURL.Hostname()
	if isPrivateIP(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private/internal addresses is not allowed"})
	}

	// Fetch the URL with a timeout and limits
	client := &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Don't follow redirects automatically
		},
	}

	// Create a new request to prevent any potential header manipulation
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit response size to prevent large payloads
	const maxBodySize = 2 * 1024 * 1024 // 2MB limit
	limitReader := io.LimitReader(resp.Body, maxBodySize)
	body, err := io.ReadAll(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	titleSelection := doc.Find("title")
	if titleSelection.Length() > 0 {
		title = strings.TrimSpace(titleSelection.First().Text())
	} else {
		// Try og:title meta tag
		doc.Find("head meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			if content, exists := s.Attr("content"); exists {
				title = strings.TrimSpace(content)
			}
		})
	}

	var description string
	// Look for meta description tag
	doc.Find("head meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if content, exists := s.Attr("content"); exists {
			description = strings.TrimSpace(content)
		}
	})

	// If no description found, try og:description
	if description == "" {
		doc.Find("head meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if content, exists := s.Attr("content"); exists {
				description = strings.TrimSpace(content)
			}
		})
	}

	return title, description
}

// isPrivateIP checks if a hostname resolves to a private IP address
func isPrivateIP(host string) bool {
	// For simplicity, we'll just check common private IP ranges
	// In a production environment, you'd want to resolve the hostname and check the actual IPs
	privatePrefixes := []string{
		"10.",     // Class A private network
		"172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.",
		"172.24.", "172.25.", "172.26.", "172.27.",
		"172.28.", "172.29.", "172.30.", "172.31.", // Class B private networks
		"192.168.", // Class C private network
		"127.",     // Loopback
		"localhost",
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(host, prefix) || strings.ToLower(host) == "localhost" {
			return true
		}
	}

	return false
}

