			Description: "",
			Error:       err.Error(),
		})
	}

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func extractPageInfo(url string) (string, string, error) {
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return "", "", fmt.Errorf("failed to create request: %w", err)
	}

	resp, err := client.Do(req)
	if err != nil {
		return "", "", fmt.Errorf("failed to fetch URL: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", "", fmt.Errorf("received non-200 status code: %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", "", fmt.Errorf("failed to read response body: %w", err)
	}

	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	// Extract title
	title := ""
	doc.Find("title").Each(func(i int, s *goquery.Selection) {
		title = strings.TrimSpace(s.Text())
	})

	if title == "" {
		// Try og:title meta tag
		doc.Find("meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			content, exists := s.Attr("content")
			if exists {
				title = strings.TrimSpace(content)
			}
		})
	}

	// Extract description
	description := ""
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		content, exists := s.Attr("content")
		if exists {
			description = strings.TrimSpace(content)
		}
	})

	if description == "" {
		// Try og:description meta tag
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			content, exists := s.Attr("content")
			if exists {
				description = strings.TrimSpace(content)
			}
		})
	}

	return title, description, nil
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

