	titleSelection := doc.Find("title")
	if titleSelection.Length() > 0 {
		title = strings.TrimSpace(titleSelection.First().Text())
	} else {
		// Try og:title meta tag
		doc.Find("meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
