	"github.com/labstack/echo/v4"
)

type RequestBody struct {
	URL string `json:"url"`
}

type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var reqBody RequestBody
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL is required",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, reqBody.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create request",
		})
	}

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to fetch URL",
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode),
		})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to read response body",
		})
	}

	title, description := extractHTMLInfo(body)

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func extractHTMLInfo(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := doc.Find("title").First().Text()
	description := ""

	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		if name, exists := s.Attr("name"); exists && strings.ToLower(name) == "description" {
			if content, exists := s.Attr("content"); exists {
				description = content
			}
		} else if name, exists := s.Attr("property"); exists && name == "og:description" {
			if content, exists := s.Attr("content"); exists {
				description = content
			}
		}
	})

	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description
}

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

