// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF attacks by ensuring the URL doesn't point to internal resources
	host := parsedURL.Hostname()
	if isLocalhost(host) || isPrivateIP(parsedURL.Host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to local or private addresses is not allowed"})
	}

	// Fetch the URL
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Prevent redirect loops and check each redirect target
			if len(via) >= 3 { // Limit redirects to prevent loops
				return fmt.Errorf("too many redirects")
			}

			host := req.URL.Hostname()
			if isLocalhost(host) || isPrivateIP(req.URL.Host) {
				return fmt.Errorf("redirects to local or private addresses are not allowed")
			}

			return nil
		},
	}

	reqObj, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	reqObj.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(reqObj)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title string
	doc.Find("title").Each(func(i int, s *goquery.Selection) {
		title = strings.TrimSpace(s.Text())
	})

	if title == "" {
		doc.Find("h1").Each(func(i int, s *goquery.Selection) {
			if title == "" {
				title = strings.TrimSpace(s.Text())
			}
		})
	}

	var description string
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		content, exists := s.Attr("content")
		if exists {
			description = strings.TrimSpace(content)
		}
	})

	return title, description
}

// Helper functions to detect localhost and private IPs
func isLocalhost(host string) bool {
	return host == "localhost" || 
		   host == "127.0.0.1" || 
		   host == "::1" ||
		   strings.HasPrefix(host, "127.")
}

func isPrivateIP(hostPort string) bool {
	// Remove port if present
	host := strings.Split(hostPort, ":")[0]

	privateCIDRs := []string{
		"10.",      // Class A private network
		"172.16.",  // Class B private network range start
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
		"192.168.", // Class C private network
		"fd",       // IPv6 unique local address
		"fc",       // IPv6 unique local address
	}

	for _, cidr := range privateCIDRs {
		if strings.HasPrefix(host, cidr) {
			return true
		}
	}

	return false
}

