// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF by ensuring the host is not a private/local address
	host := parsedURL.Hostname()
	if isPrivateAddress(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private addresses is not allowed"})
	}

	// Fetch the URL
	client := &http.Client{
		Timeout: 5 * time.Second, // Increased timeout slightly for real-world usage
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Prevent redirects to private addresses
			host := req.URL.Hostname()
			if isPrivateAddress(host) {
				return fmt.Errorf("redirect to private address blocked")
			}
			return nil
		},
	}

	reqObj, err := http.NewRequest(http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	reqObj.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(reqObj)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string

	// Extract title
	titleSelection := doc.Find("title")
	if titleSelection.Length() > 0 {
		title = strings.TrimSpace(titleSelection.First().Text())
	} else {
		// Try og:title meta tag
		doc.Find("head meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				title = strings.TrimSpace(val)
			}
		})
	}

	// Extract description
	doc.Find("head meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if val, exists := s.Attr("content"); exists {
			description = strings.TrimSpace(val)
		}
	})

	// Fallback to og:description
	if description == "" {
		doc.Find("head meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				description = strings.TrimSpace(val)
			}
		})
	}

	return title, description
}

// Check if host is a private/local address to prevent SSRF
func isPrivateAddress(host string) bool {
	privateIPs := []string{"localhost", "127.0.0.1", "::1", "0.0.0.0"}
	for _, ip := range privateIPs {
		if strings.EqualFold(host, ip) {
			return true
		}
	}

	// Check for internal domains that might resolve to private IPs
	privateSuffixes := []string{".internal", ".local", ".svc.cluster.local"}
	for _, suffix := range privateSuffixes {
		if strings.HasSuffix(strings.ToLower(host), suffix) {
			return true
		}
	}

	return false
}

