)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create request",
		})
	}

	// Make the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Failed to read response body: %v", err),
		})
	}

	// Parse HTML
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Failed to parse HTML: %v", err),
		})
	}

	// Extract title
	title := ""
	doc.Find("title").Each(func(i int, s *goquery.Selection) {
		title = strings.TrimSpace(s.Text())
	})

	// Extract meta description
	description := ""
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		content, exists := s.Attr("content")
		if exists {
			description = strings.TrimSpace(content)
		}
	})

	// If no meta description found, try property="og:description"
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			content, exists := s.Attr("content")
			if exists {
				description = strings.TrimSpace(content)
			}
		})
	}

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

