		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode),
		})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to read response body",
		})
	}

	title, description := extractMetadata(string(body))

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func extractMetadata(htmlContent string) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	doc.Find("title").Each(func(i int, s *goquery.Selection) {
		title = strings.TrimSpace(s.Text())
	})

	if title == "" {
		doc.Find("h1").Each(func(i int, s *goquery.Selection) {
			if title == "" {
				title = strings.TrimSpace(s.Text())
			}
		})
	}

	var description string
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		desc, exists := s.Attr("content")
		if exists {
			description = strings.TrimSpace(desc)
		}
	})

	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			desc, exists := s.Attr("content")
			if exists {
				description = strings.TrimSpace(desc)
			}
		})
	}

	return title, description
}

