package main

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

type RequestBody struct {
	URL string `json:"url"`
}

type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var reqBody RequestBody
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	req, err := http.NewRequestWithContext(context.Background(), "GET", reqBody.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create request",
		})
	}

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("Received non-OK status: %d", resp.StatusCode),
		})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to read response body",
		})
	}

	title, description := parseHTML(string(body))

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func parseHTML(htmlContent string) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	// Extract title
	titleSelection := doc.Find("title")
	if titleSelection.Length() > 0 {
		title = strings.TrimSpace(titleSelection.First().Text())
	} else {
		// Try og:title meta tag
		doc.Find("meta[property='og:title']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				title = strings.TrimSpace(val)
			}
		})
	}

	// Extract description
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if val, exists := s.Attr("content"); exists {
			description = strings.TrimSpace(val)
		}
	})

	// If no description found, try og:description
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if val, exists := s.Attr("content"); exists {
				description = strings.TrimSpace(val)
			}
		})
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

